import { useStore } from '../store';
import { shallow } from 'zustand/shallow';
import { Settings, Type, Sparkles, Globe, Filter, Wrench, GitMerge, AlignLeft } from 'lucide-react';

const selector = (s) => ({ nodes: s.nodes, updateNodeField: s.updateNodeField });

const fieldStyle = {
  label: {
    display: 'block',
    fontSize: '11px',
    fontWeight: 600,
    letterSpacing: '0.04em',
    color: 'var(--text-secondary)',
    marginBottom: '6px',
  },
  input: {
    width: '100%',
    background: 'var(--bg-app)',
    border: '1px solid var(--border-subtle)',
    borderRadius: '6px',
    padding: '8px 12px',
    fontSize: '13px',
    color: 'var(--text-primary)',
    outline: 'none',
    boxSizing: 'border-box',
    transition: 'border-color 0.15s',
  },
  select: {
    width: '100%',
    background: 'var(--bg-app)',
    border: '1px solid var(--border-subtle)',
    borderRadius: '6px',
    padding: '8px 12px',
    fontSize: '13px',
    color: 'var(--text-primary)',
    outline: 'none',
    boxSizing: 'border-box',
    cursor: 'pointer',
    appearance: 'none',
  },
  group: {
    marginBottom: '20px',
  },
};

const NodeSettings = ({ node, updateNodeField }) => {
  const { id, type, data } = node;

  const handleChange = (field, value) => {
    updateNodeField(id, field, value);
  };

  switch (type) {
    case 'customInput':
    case 'customOutput':
      return (
        <div style={fieldStyle.group}>
          <label style={fieldStyle.label}>Name</label>
          <input
            style={fieldStyle.input}
            value={data[`${type.replace('custom', '').toLowerCase()}Name`] || ''}
            onChange={(e) => handleChange(`${type.replace('custom', '').toLowerCase()}Name`, e.target.value)}
            placeholder="Name..."
          />
          <label style={{ ...fieldStyle.label, marginTop: 16 }}>Type</label>
          <select
            style={fieldStyle.select}
            value={data[`${type.replace('custom', '').toLowerCase()}Type`] || 'Text'}
            onChange={(e) => handleChange(`${type.replace('custom', '').toLowerCase()}Type`, e.target.value)}
          >
            <option value="Text">Text</option>
            <option value="File">File</option>
          </select>
        </div>
      );
    case 'text':
      return (
        <div style={fieldStyle.group}>
          <label style={fieldStyle.label}>Content</label>
          <textarea
            style={{ ...fieldStyle.input, minHeight: '120px', resize: 'vertical', fontFamily: 'monospace', fontSize: '12px' }}
            value={data.text || '{{input}}'}
            onChange={(e) => handleChange('text', e.target.value)}
          />
          <div style={{ fontSize: '11px', color: 'var(--text-tertiary)', marginTop: '8px' }}>
            Use {'{{variable}}'} to create dynamic inputs.
          </div>
        </div>
      );
    case 'llm':
      return (
        <>
          <div style={fieldStyle.group}>
            <label style={fieldStyle.label}>Model</label>
            <select style={fieldStyle.select} value={data.model || 'gpt-4o'} onChange={(e) => handleChange('model', e.target.value)}>
              <option value="gpt-4o">GPT-4o</option>
              <option value="gpt-4-turbo">GPT-4 Turbo</option>
              <option value="claude-3-5-sonnet">Claude 3.5 Sonnet</option>
              <option value="gemini-1.5-pro">Gemini 1.5 Pro</option>
            </select>
          </div>
          <div style={fieldStyle.group}>
            <label style={fieldStyle.label}>Temperature ({data.temperature || '0.7'})</label>
            <input
              type="range"
              min="0"
              max="2"
              step="0.1"
              style={{ width: '100%', cursor: 'pointer' }}
              value={data.temperature || '0.7'}
              onChange={(e) => handleChange('temperature', e.target.value)}
            />
          </div>
        </>
      );
    default:
      return (
        <div style={{ fontSize: '13px', color: 'var(--text-secondary)' }}>
          No specific configuration available for this node type.
        </div>
      );
  }
};

export const RightSidebar = () => {
  const { nodes, updateNodeField } = useStore(selector, shallow);
  const selectedNode = nodes.find((n) => n.selected);

  return (
    <div
      style={{
        width: '320px',
        background: 'var(--bg-surface)',
        borderLeft: '1px solid var(--border-subtle)',
        display: 'flex',
        flexDirection: 'column',
        height: 'calc(100vh - 56px)',
        zIndex: 10,
      }}
    >
      <div style={{ padding: '16px 20px', borderBottom: '1px solid var(--border-subtle)', display: 'flex', alignItems: 'center', gap: '8px' }}>
        <Settings size={16} color="var(--text-secondary)" />
        <span style={{ fontSize: '13px', fontWeight: 600, color: 'var(--text-primary)' }}>Inspector</span>
      </div>

      <div style={{ flex: 1, overflowY: 'auto', padding: '20px' }}>
        {selectedNode ? (
          <div>
            <div style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '24px' }}>
              <div style={{ width: 32, height: 32, borderRadius: '6px', background: 'var(--bg-app)', border: '1px solid var(--border-subtle)', display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'var(--accent-blue)' }}>
                {/* Dynamically render icon based on type would be nice, using generic for now */}
                <AlignLeft size={16} />
              </div>
              <div>
                <div style={{ fontSize: '14px', fontWeight: 600, color: 'var(--text-primary)', textTransform: 'capitalize' }}>
                  {selectedNode.type.replace('custom', '')} Node
                </div>
                <div style={{ fontSize: '11px', color: 'var(--text-tertiary)', fontFamily: 'monospace' }}>
                  {selectedNode.id}
                </div>
              </div>
            </div>

            <div style={{ borderTop: '1px solid var(--border-subtle)', paddingTop: '20px' }}>
              <NodeSettings node={selectedNode} updateNodeField={updateNodeField} />
            </div>
          </div>
        ) : (
          <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', height: '100%', color: 'var(--text-tertiary)', textAlign: 'center', gap: '12px' }}>
            <Settings size={32} opacity={0.5} />
            <span style={{ fontSize: '13px' }}>Select a node to view its configuration.</span>
          </div>
        )}
      </div>
    </div>
  );
};
